import React, { useEffect, useState } from 'react';
import axios from 'axios';
import { Trophy, Heart, Play, Headphones } from 'lucide-react';
import { useMusic } from '../../context/MusicContext';

const Ranking = () => {
  const [topSongs, setTopSongs] = useState([]);
  const { favorites, toggleLike, playMusic } = useMusic();

  useEffect(() => {
    axios.get('http://localhost:5000/api/songs/ranking')
      .then(res => setTopSongs(res.data))
      .catch(err => console.error(err));
  }, []);

  return (
    <div style={rankPage}>
      <header style={rankHeader}>
        <Trophy size={60} color="#FFD700" />
        <h1 style={{ fontSize: '32px', margin: '10px 0' }}>BẢNG XẾP HẠNG</h1>
        <p style={{ color: '#b3b3b3' }}>Những bài hát được nghe nhiều nhất tuần này</p>
      </header>

      <div style={rankList}>
        {topSongs.map((song, index) => {
          const isLiked = favorites.includes(String(song._id));

          return (
            <div 
              key={song._id} 
              style={rankItemStyle(index)}
              onClick={() => playMusic(topSongs, index)} // Click cả dòng để phát nhạc
            >
              <div style={rankNumberStyle(index)}>{index + 1}</div>
              
              <img src={`http://localhost:5000${song.imageUrl}`} style={rankImg} alt="" />
              
              <div style={{ flex: 1 }}>
                <div style={songName}>{song.title || song.name}</div>
                <div style={songArt}>{song.artist || song.singer}</div>
              </div>

              <div style={statsContainer}>
                <div style={statItem}>
                  <Headphones size={16} color="#1db954" />
                  <span>{song.playCount || 0}</span>
                </div>
                
                {/* Nút Like (Dùng stopPropagation để không bị kích hoạt sự kiện phát nhạc của hàng) */}
                <button 
                  onClick={(e) => { e.stopPropagation(); toggleLike(song._id); }} 
                  style={btnTransparent}
                >
                  <Heart 
                    size={18} 
                    fill={isLiked ? "#ff4d4d" : "none"} 
                    color={isLiked ? "#ff4d4d" : "#555"} 
                  />
                </button>
              </div>
            </div>
          );
        })}
      </div>
    </div>
  );
};

// Styles Ranking
const rankPage = { padding: '40px 20px', maxWidth: '850px', margin: '0 auto', color: '#fff', paddingBottom: '120px' };
const rankHeader = { textAlign: 'center', marginBottom: '40px' };
const rankList = { background: '#181818', borderRadius: '16px', overflow: 'hidden' };

const rankItemStyle = (i) => ({ 
  display: 'flex', alignItems: 'center', padding: '15px 25px', borderBottom: '1px solid #282828',
  cursor: 'pointer', transition: '0.2s',
  background: i === 0 ? 'rgba(255, 215, 0, 0.05)' : 'transparent',
  ':hover': { background: '#222' }
});

const rankNumberStyle = (i) => ({ 
  fontSize: '20px', fontWeight: 'bold', width: '40px', 
  color: i === 0 ? '#FFD700' : i === 1 ? '#C0C0C0' : i === 2 ? '#CD7F32' : '#777' 
});

const rankImg = { width: '50px', height: '50px', borderRadius: '4px', marginRight: '20px', objectFit: 'cover' };
const songName = { fontSize: '16px', fontWeight: '600', color: '#fff' };
const songArt = { fontSize: '13px', color: '#b3b3b3' };
const statsContainer = { display: 'flex', gap: '20px', alignItems: 'center' };
const statItem = { display: 'flex', alignItems: 'center', gap: '6px', color: '#b3b3b3', fontSize: '14px' };
const btnTransparent = { background: 'none', border: 'none', cursor: 'pointer', padding: 5 };

export default Ranking;
